48	const PROCESSING_FEE = 5;
49	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
50	
51	const BASE_PREMIUMS: Record<string, number> = {
52	  sword: 100,
53	  amulet: 60,
54	  staff: 80,
55	  potion: 40,
56	  rune: 25,
57	};
58	
59	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
60	
61	const sumBasePremiums = (items: Item[]): number =>
62	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
63	
64	const quotePremium = (items: Item[]): number => {
65	  const base = sumBasePremiums(items);
66	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
67	  return base + firstInsuranceSurcharge + PROCESSING_FEE;
68	};
69	
70	const claimPayout = (_step: ClaimStep): StepResult => ({
71	  payout: 0,
72	  remainingCap: 0,
73	});
74	
75	const runStep = (step: Step): StepResult =>
76	  step.op === "quote"
77	    ? { premium: quotePremium(step.items) }
78	    : claimPayout(step);
79	
80	export const runScenario = (scenario: Scenario): ScenarioResult => {
81	  return { results: scenario.steps.map(runStep) };
82	};
